mapper.select:
SELECT , u.nickname as username, u.avatar as user_avatar, pu.nickname as reply_to_username FROM comment c LEFT JOIN user u ON c.user_id = u.id LEFT JOIN comment pc ON c.parent_id = pc.id LEFT JOIN user pu ON pc.user_id = pu.id WHERE c.article_id = #{articleId}
AND c.status = #{status}
ORDER BY c.create_time DESC

mapper.update:
UPDATE comment

    content = #{content},
    status = #{status}

WHERE id = #{id}
